import{_ as i,o as a,c as t,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"竞品定价、文档、演示、更新日志与下线功能","description":"","frontmatter":{},"headers":[],"relativePath":"02-product/notes/02-problem-evidence/06-pricing-docs-demos-changelogs-sunsets.md","filePath":"02-product/notes/02-problem-evidence/06-pricing-docs-demos-changelogs-sunsets.md","lastUpdated":1784542968000}'),s={name:"02-product/notes/02-problem-evidence/06-pricing-docs-demos-changelogs-sunsets.md"};function n(r,l,o,p,d,h){return a(),t("div",null,[...l[0]||(l[0]=[e(`<h1 id="竞品定价、文档、演示、更新日志与下线功能" tabindex="-1">竞品定价、文档、演示、更新日志与下线功能 <a class="header-anchor" href="#竞品定价、文档、演示、更新日志与下线功能" aria-label="Permalink to &quot;竞品定价、文档、演示、更新日志与下线功能&quot;">​</a></h1><p>分析一个持续变化的产品，需要把定价、能力文档、演示观察、更新日志和下线公告放进同一条时间线。五类材料证明的事情不同：只有联合证据才能回答“谁能购买、能用什么、按什么计费、当前是否可用、未来是否仍可依赖”。</p><h2 id="一、五类材料的证明边界" tabindex="-1">一、五类材料的证明边界 <a class="header-anchor" href="#一、五类材料的证明边界" aria-label="Permalink to &quot;一、五类材料的证明边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>材料</th><th>主要证明</th><th>不能单独证明</th></tr></thead><tbody><tr><td>定价与套餐页</td><td>公开包装、标价、计费单位、公开限制</td><td>企业合同总价、所有附加费、实际效果</td></tr><tr><td>产品文档</td><td>官方描述的前置条件、规则、限制和配置</td><td>所有账号已获得能力、真实规模性能</td></tr><tr><td>演示、试用或截图</td><td>指定账号、数据、版本和时间下的可见行为</td><td>普遍可用、稳定性、服务承诺</td></tr><tr><td>更新日志或发布说明</td><td>提供方在某日宣称新增、变更或修复</td><td>用户已采用、缺陷全部解决、长期保留</td></tr><tr><td>下线公告</td><td>停止新增、弃用、停止服务或删除的范围与日期</td><td>未明确说明的内部原因、迁移一定无损</td></tr></tbody></table><p>这五类证据不能互相替代。营销页写“支持代码审查”，仍需文档确认支持的计划、仓库、权限和计费；试用中成功一次，仍需确认正式套餐和生产限制；更新日志写“一般可用”，也不等于服务永不变更。</p><h2 id="二、能力、可获得性与承诺是三件事" tabindex="-1">二、能力、可获得性与承诺是三件事 <a class="header-anchor" href="#二、能力、可获得性与承诺是三件事" aria-label="Permalink to &quot;二、能力、可获得性与承诺是三件事&quot;">​</a></h2><h3 id="能力" tabindex="-1">能力 <a class="header-anchor" href="#能力" aria-label="Permalink to &quot;能力&quot;">​</a></h3><p>能力是产品在某些条件下可以执行的动作，例如生成建议、调用模型、导出报告或运行代理。描述能力必须附带输入、输出、权限、平台、规模和失败状态。</p><h3 id="可获得性" tabindex="-1">可获得性 <a class="header-anchor" href="#可获得性" aria-label="Permalink to &quot;可获得性&quot;">​</a></h3><p>可获得性回答目标用户当前能否拿到能力，取决于：</p><ul><li>地区与账号资格；</li><li>新购是否开放；</li><li>套餐、附加包和席位；</li><li>管理员策略；</li><li>客户端与最低版本；</li><li>灰度、预览或候补名单；</li><li>用量配额、预算和速率限制。</li></ul><p>“文档里存在”不保证目标账号可见。“已一般可用”也可能仍受计划、策略或地区限制。</p><h3 id="承诺" tabindex="-1">承诺 <a class="header-anchor" href="#承诺" aria-label="Permalink to &quot;承诺&quot;">​</a></h3><p>承诺是提供方在合同、服务条款、SLA、弃用政策或正式公告中承担的持续责任。产品文案和演示通常不是服务等级承诺；预览能力可能变更或移除；公开路线图表示计划而非保证。</p><p>分析时至少区分：</p><ol><li><strong>已文档化能力</strong>：官方页面描述当前规则；</li><li><strong>已观察行为</strong>：目标环境中实际发生；</li><li><strong>合同承诺</strong>：正式条款覆盖的责任；</li><li><strong>分析者推断</strong>：根据变化节奏推测投入方向；</li><li><strong>待验证假设</strong>：真实业务中可能产生的效果。</li></ol><h2 id="三、定价不是一个数字-而是一组函数" tabindex="-1">三、定价不是一个数字，而是一组函数 <a class="header-anchor" href="#三、定价不是一个数字-而是一组函数" aria-label="Permalink to &quot;三、定价不是一个数字，而是一组函数&quot;">​</a></h2><h3 id="_1-固定观察条件" tabindex="-1">1. 固定观察条件 <a class="header-anchor" href="#_1-固定观察条件" aria-label="Permalink to &quot;1. 固定观察条件&quot;">​</a></h3><p>记录价格时，至少保存：</p><ul><li>观察日期与页面版本；</li><li>购买主体和资格；</li><li>国家或地区；</li><li>币种；</li><li>是否含税；</li><li>月付、年付或承诺期；</li><li>计划名称；</li><li>计费单位；</li><li>包含量；</li><li>超额单价；</li><li>最低消费与最低席位；</li><li>免费层、试用和促销条件；</li><li>取消、退款和降级条件。</li></ul><p>未固定这些条件时，“每月 10 美元”无法与另一个产品比较。</p><h3 id="_2-识别计费单位" tabindex="-1">2. 识别计费单位 <a class="header-anchor" href="#_2-识别计费单位" aria-label="Permalink to &quot;2. 识别计费单位&quot;">​</a></h3><p>常见计费单位包括：</p><ul><li>每用户或每席位；</li><li>每活跃用户；</li><li>每请求、调用或任务；</li><li>每输入、输出或缓存 token；</li><li>每 GB 存储或传输；</li><li>每执行分钟、计算时长或构建分钟；</li><li>每交易金额或成功交易；</li><li>分层用量；</li><li>基础订阅加用量；</li><li>企业合同的最低承诺。</li></ul><p>席位价格解释组织规模，用量价格解释行为规模。两者叠加时，要把固定成本和变量成本分开。</p><h3 id="_3-建立总成本公式" tabindex="-1">3. 建立总成本公式 <a class="header-anchor" href="#_3-建立总成本公式" aria-label="Permalink to &quot;3. 建立总成本公式&quot;">​</a></h3><p>一个订阅加用量产品可写为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>月度可见成本</span></span>
<span class="line"><span>= 可计费席位 × 席位单价</span></span>
<span class="line"><span>+ 超出包含量的用量 × 超额单价</span></span>
<span class="line"><span>+ 关联基础设施用量</span></span>
<span class="line"><span>+ 税费</span></span>
<span class="line"><span>+ 明示附加服务</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>真实总拥有成本还包括实施、数据迁移、管理员、培训、人工复核、失败恢复、审计、退出和替代供应商成本。公开定价页通常不能提供这些内部数字，应由自己的任务数据补齐。</p><h3 id="_4-计算三种负载" tabindex="-1">4. 计算三种负载 <a class="header-anchor" href="#_4-计算三种负载" aria-label="Permalink to &quot;4. 计算三种负载&quot;">​</a></h3><p>不要只算平均月：</p><ul><li><strong>典型负载</strong>：正常月份的席位和用量；</li><li><strong>峰值负载</strong>：发布、迁移或集中交付月份；</li><li><strong>失败负载</strong>：重试、重复生成、人工复核和降级导致的额外成本。</li></ul><p>如果模型、推理级别或上下文长度改变单次用量，成本模型应按实际调用日志分段，不能用一个平均单价覆盖全部模型。</p><h2 id="四、能力文档的逐项核对" tabindex="-1">四、能力文档的逐项核对 <a class="header-anchor" href="#四、能力文档的逐项核对" aria-label="Permalink to &quot;四、能力文档的逐项核对&quot;">​</a></h2><p>阅读文档时，从用户任务反向提取：</p><h3 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h3><ul><li>需要哪个计划、账号和组织类型；</li><li>管理员必须启用哪些策略；</li><li>支持哪些客户端、浏览器、IDE 或 API 版本；</li><li>是否需要额外存储、运行器、密钥或第三方账号。</li></ul><h3 id="输入与输出" tabindex="-1">输入与输出 <a class="header-anchor" href="#输入与输出" aria-label="Permalink to &quot;输入与输出&quot;">​</a></h3><ul><li>接受哪些文件、数据类型、大小和编码；</li><li>输出是建议、确定性结果还是概率性生成；</li><li>是否包含来源、日志、版本和可追踪 ID；</li><li>输出如何导出、删除和纠错。</li></ul><h3 id="限制与失败" tabindex="-1">限制与失败 <a class="header-anchor" href="#限制与失败" aria-label="Permalink to &quot;限制与失败&quot;">​</a></h3><ul><li>配额、速率、并发和上下文限制；</li><li>权限不足和策略禁用时的行为；</li><li>网络、供应商或模型不可用时如何降级；</li><li>预览能力是否可能随时变化；</li><li>支持渠道与问题恢复范围。</li></ul><h3 id="数据与安全" tabindex="-1">数据与安全 <a class="header-anchor" href="#数据与安全" aria-label="Permalink to &quot;数据与安全&quot;">​</a></h3><ul><li>数据发送给谁；</li><li>保存多长时间；</li><li>是否用于训练或评估；</li><li>组织策略能否控制；</li><li>审计日志和区域限制；</li><li>删除、导出和法律请求流程。</li></ul><p>分析者只能写文档明确说明的内容。页面没有写最大规模时，不能根据一次小样本演示猜测上限。</p><h2 id="五、演示只证明指定条件下的一次观察" tabindex="-1">五、演示只证明指定条件下的一次观察 <a class="header-anchor" href="#五、演示只证明指定条件下的一次观察" aria-label="Permalink to &quot;五、演示只证明指定条件下的一次观察&quot;">​</a></h2><h3 id="_1-建立演示协议" tabindex="-1">1. 建立演示协议 <a class="header-anchor" href="#_1-建立演示协议" aria-label="Permalink to &quot;1. 建立演示协议&quot;">​</a></h3><p>演示前固定：</p><ul><li>账号、计划和组织策略；</li><li>客户端、版本、操作系统和地区；</li><li>输入数据、规模和敏感级别；</li><li>任务与完成标准；</li><li>允许的人工干预；</li><li>网络和依赖；</li><li>开始、结束时间；</li><li>预期错误与恢复方法。</li></ul><p>演示数据应覆盖正常、空输入、权限不足、超限、失败和恢复。只演示理想路径无法验证生产可用性。</p><h3 id="_2-保存可观察结果" tabindex="-1">2. 保存可观察结果 <a class="header-anchor" href="#_2-保存可观察结果" aria-label="Permalink to &quot;2. 保存可观察结果&quot;">​</a></h3><p>记录：</p><ul><li>实际输入与输出；</li><li>请求或任务 ID；</li><li>响应时间和完成状态；</li><li>错误文本；</li><li>权限提示；</li><li>用量记录；</li><li>是否需要人工修正；</li><li>重新登录、刷新或重试后的状态。</li></ul><p>截图只能佐证界面状态。涉及生成式输出时，还要保存输入、选择的模型类别、结构校验、人工评估标准和失败样本。</p><h3 id="_3-区分供应商演示和亲自验证" tabindex="-1">3. 区分供应商演示和亲自验证 <a class="header-anchor" href="#_3-区分供应商演示和亲自验证" aria-label="Permalink to &quot;3. 区分供应商演示和亲自验证&quot;">​</a></h3><p>供应商演示通常使用准备好的数据、权限和理想路径。它可以证明“提供方展示过该行为”。亲自试用能证明“目标账号在观察日完成过该任务”。两者都不能证明 SLA、所有数据规模或未来可用。</p><p>若无法获得试用账号，正确状态是“未验证”，不是根据视频补写观察结果。</p><h2 id="六、更新日志是一条事件记录-不是当前真相" tabindex="-1">六、更新日志是一条事件记录，不是当前真相 <a class="header-anchor" href="#六、更新日志是一条事件记录-不是当前真相" aria-label="Permalink to &quot;六、更新日志是一条事件记录，不是当前真相&quot;">​</a></h2><p>更新日志应提取：</p><ul><li>事件日期；</li><li>变化类型：预览、一般可用、修复、计费变更、弃用或下线；</li><li>影响对象：计划、客户端、API、模型或地区；</li><li>是否需要管理员动作；</li><li>生效日与迁移截止日；</li><li>对应文档和当前状态。</li></ul><p>常见时间差包括：</p><ul><li>公告日早于实际开放日；</li><li>分批发布导致不同账号不同步；</li><li>文档更新晚于产品变化；</li><li>一般可用后仍需策略启用；</li><li>修复发布后客户端尚未升级；</li><li>新能力上线后旧能力进入弃用。</li></ul><p>因此，每条日志都要再回到当前文档和目标账号验证。历史日志适合解释变化时间，不应覆盖当前状态。</p><h2 id="七、下线不是一个瞬间-而是生命周期" tabindex="-1">七、下线不是一个瞬间，而是生命周期 <a class="header-anchor" href="#七、下线不是一个瞬间-而是生命周期" aria-label="Permalink to &quot;七、下线不是一个瞬间，而是生命周期&quot;">​</a></h2><h3 id="_1-术语可能不同" tabindex="-1">1. 术语可能不同 <a class="header-anchor" href="#_1-术语可能不同" aria-label="Permalink to &quot;1. 术语可能不同&quot;">​</a></h3><p>不同提供方会使用 <code>deprecated</code>、<code>retired</code>、<code>sunset</code>、<code>end of support</code>、<code>end of sale</code>、<code>end of life</code>。这些词没有跨供应商统一含义，必须阅读该公告给出的实际动作。</p><h3 id="_2-至少记录五个日期" tabindex="-1">2. 至少记录五个日期 <a class="header-anchor" href="#_2-至少记录五个日期" aria-label="Permalink to &quot;2. 至少记录五个日期&quot;">​</a></h3><ul><li>宣布日期；</li><li>停止新购或停止创建日期；</li><li>弃用或开始迁移日期；</li><li>破坏性演练或 brownout 日期；</li><li>完全停止服务和数据处理日期。</li></ul><p>如果公告只给一个日期，其余保持未知。</p><h3 id="_3-评估影响面" tabindex="-1">3. 评估影响面 <a class="header-anchor" href="#_3-评估影响面" aria-label="Permalink to &quot;3. 评估影响面&quot;">​</a></h3><p>逐项检查：</p><ul><li>UI、API、SDK、模型和 Marketplace 条目是否同时停止；</li><li>现有客户与新客户是否不同；</li><li>哪些请求会返回什么错误；</li><li>已保存配置、历史结果和日志是否仍可访问；</li><li>数据导出格式与截止日；</li><li>推荐替代是否功能等价；</li><li>身份、权限、模型、提示、评估和账单如何迁移；</li><li>回滚窗口、双跑成本和负责人。</li></ul><p>“提供了替代方案”不证明迁移无成本。需要在相同任务与数据上重新验证质量、性能、权限、费用和合规。</p><h3 id="_4-不猜下线原因" tabindex="-1">4. 不猜下线原因 <a class="header-anchor" href="#_4-不猜下线原因" aria-label="Permalink to &quot;4. 不猜下线原因&quot;">​</a></h3><p>只有官方明确说明的原因可写成事实。根据发布频率、价格或竞争格局得出的解释应标为推断。产品研究通常不需要知道内部原因才能做出迁移决策；截止日期和影响范围更重要。</p><h2 id="八、建立联合证据矩阵" tabindex="-1">八、建立联合证据矩阵 <a class="header-anchor" href="#八、建立联合证据矩阵" aria-label="Permalink to &quot;八、建立联合证据矩阵&quot;">​</a></h2><p>每个待比较能力占一行：</p><table tabindex="0"><thead><tr><th>字段</th><th>记录内容</th></tr></thead><tbody><tr><td>任务</td><td>用户实际要完成的结果</td></tr><tr><td>计划与资格</td><td>谁可以获得</td></tr><tr><td>定价</td><td>币种、周期、计费单位、包含量和超额</td></tr><tr><td>文档能力</td><td>前置、输入、输出、限制、失败</td></tr><tr><td>演示观察</td><td>账号、版本、数据、结果和错误</td></tr><tr><td>发布事件</td><td>公告日、GA 状态和需要的动作</td></tr><tr><td>生命周期</td><td>弃用、停止新建、brownout、完全下线</td></tr><tr><td>承诺</td><td>合同、SLA 或弃用政策是否覆盖</td></tr><tr><td>证据状态</td><td>事实、观察、推断或假设</td></tr><tr><td>决策</td><td>采用、试验、等待、迁移或拒绝</td></tr></tbody></table><p>证据强度不是简单分数。定价事实不能增强性能主张；演示成功不能增强长期承诺。每个主张只能由同类型证据支持。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;任务与目标账号&quot;] --&gt; B[&quot;定价：能否购买、怎样计费&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; C[&quot;文档：能力与限制&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D[&quot;演示：目标环境的行为&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; E[&quot;联合证据矩阵&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; E</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F[&quot;更新日志：变化时间&quot;] --&gt; E</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G[&quot;下线公告：停止范围与日期&quot;] --&gt; E</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; H[&quot;当前可用性&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; I[&quot;成本区间&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; J[&quot;迁移与承诺风险&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="九、完整案例-12-人团队选择-github-ai-开发路径" tabindex="-1">九、完整案例：12 人团队选择 GitHub AI 开发路径 <a class="header-anchor" href="#九、完整案例-12-人团队选择-github-ai-开发路径" aria-label="Permalink to &quot;九、完整案例：12 人团队选择 GitHub AI 开发路径&quot;">​</a></h2><h3 id="_1-决策与证据输入" tabindex="-1">1. 决策与证据输入 <a class="header-anchor" href="#_1-决策与证据输入" aria-label="Permalink to &quot;1. 决策与证据输入&quot;">​</a></h3><p>观察日期为 2026-07-17。一个 12 人开发团队准备为代码协作增加 AI 能力，需要判断：新工作流是否应依赖 GitHub Models，或先验证 GitHub Copilot。</p><p>公开证据如下。</p><p><strong>定价与套餐事实</strong>：GitHub 的 Copilot 计划页在观察日列出 Copilot Business 为每授予席位每月 19 美元，Copilot Enterprise 为每授予席位每月 39 美元；各计划包含不同的 AI credits 配额。计划页同时说明具体功能因计划而异。</p><p><strong>用量事实</strong>：GitHub 的模型与定价文档说明交互消耗输入、输出和缓存 token，并转换为 AI credits；1 AI credit 等于 0.01 美元。超出计划包含量后的费用取决于模型和 token。代码审查还可能同时消耗 AI credits 与 GitHub Actions 分钟。</p><p><strong>能力事实</strong>：支持模型文档列出不同模型、发布状态、支持的 Copilot 表面、计划和退役历史。模型是否出现还会受计划、客户端和组织策略影响。</p><p><strong>发布事实</strong>：GitHub Changelog 于 2026-06-17 宣布 GitHub Copilot app 一般可用，并列出从 issue、pull request 或提示创建会话、使用分支和 worktree 等能力；Business 或 Enterprise 用户还需组织启用 Copilot CLI 策略。</p><p><strong>下线事实</strong>：GitHub 于 2026-07-01 宣布 GitHub Models 将在 2026-07-30 完全停止，范围包括 playground、model catalog、inference API 和 BYOK。公告列出 2026-07-16 与 2026-07-23 的短时 brownout，并指出停止后所有客户都受影响。</p><p><strong>缺失证据</strong>：团队尚未获得目标组织中的试用记录，没有验证私有仓库、组织策略、代码审查、模型选择和失败恢复，也没有读取具体合同、税费和数据处理条款。</p><h3 id="_2-第一步-阻止错误合并" tabindex="-1">2. 第一步：阻止错误合并 <a class="header-anchor" href="#_2-第一步-阻止错误合并" aria-label="Permalink to &quot;2. 第一步：阻止错误合并&quot;">​</a></h3><p>GitHub Models 与 GitHub Copilot 是不同产品路径。不能因为两者都提供模型访问，就把 GitHub Models 的下线日期解释为 Copilot 下线；也不能把公告推荐 Copilot 理解为功能、API 和成本完全等价。</p><p>联合矩阵先写成：</p><table tabindex="0"><thead><tr><th>判断</th><th>GitHub Models</th><th>GitHub Copilot</th></tr></thead><tbody><tr><td>新依赖生命周期</td><td>2026-07-30 完全停止</td><td>当前有计划与文档，长期承诺待合同确认</td></tr><tr><td>API 等价</td><td>不适用，现路径将停止</td><td>未证明提供相同推理 API</td></tr><tr><td>组织协作能力</td><td>不再作为新方案验证</td><td>文档和发布说明提供候选能力</td></tr><tr><td>目标账号实测</td><td>未验证</td><td>未验证</td></tr><tr><td>当前决策</td><td>拒绝作为新生产依赖</td><td>进入受控试验</td></tr></tbody></table><h3 id="_3-第二步-计算可见成本下界" tabindex="-1">3. 第二步：计算可见成本下界 <a class="header-anchor" href="#_3-第二步-计算可见成本下界" aria-label="Permalink to &quot;3. 第二步：计算可见成本下界&quot;">​</a></h3><p>若团队符合 Copilot Business 购买条件，并为 12 人全部授予席位，则公开席位费下界为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>12 席位 × 19 美元/席位/月 = 228 美元/月</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个数不是总价，因为尚缺：</p><ul><li>计划包含的 AI credits 与实际消耗；</li><li>超额 token 对应的模型单价；</li><li>代码审查产生的 Actions 分钟；</li><li>税费、币种转换和合同条件；</li><li>实施、策略管理、培训与人工复核；</li><li>若部分成员无需席位，实际授予数可能低于 12。</li></ul><p>总成本模型写为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>月成本</span></span>
<span class="line"><span>= 已授予席位 × 19 美元</span></span>
<span class="line"><span>+ max(0, 实际 AI credits - 计划包含量) × 0.01 美元</span></span>
<span class="line"><span>+ 额外 GitHub Actions 分钟费用</span></span>
<span class="line"><span>+ 税费与内部运营成本</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>实际模型价格和包含量必须在购买日重新读取官方页面，并用团队用量报告填入，不能把观察日数字永久写入预算。</p><h3 id="_4-第三步-把文档能力转换成试验条件" tabindex="-1">4. 第三步：把文档能力转换成试验条件 <a class="header-anchor" href="#_4-第三步-把文档能力转换成试验条件" aria-label="Permalink to &quot;4. 第三步：把文档能力转换成试验条件&quot;">​</a></h3><p>团队选择三个真实任务：</p><ol><li>从一个已批准的 issue 创建隔离工作分支并生成可审查 diff；</li><li>对一个固定 pull request 执行代码审查；</li><li>在受控仓库中使用两个允许模型完成同一修复。</li></ol><p>每个任务记录：</p><ul><li>计划和授予席位；</li><li>组织策略；</li><li>客户端及版本；</li><li>仓库权限；</li><li>选择模型；</li><li>输入上下文；</li><li>AI credits、Actions 分钟和完成时间；</li><li>diff 正确性、测试、安全检查和人工返工；</li><li>权限不足、模型不可用和预算耗尽时的错误。</li></ul><p>没有这些记录前，证据状态保持“文档化但未在目标环境验证”。</p><h3 id="_5-第四步-处理下线时间线" tabindex="-1">5. 第四步：处理下线时间线 <a class="header-anchor" href="#_5-第四步-处理下线时间线" aria-label="Permalink to &quot;5. 第四步：处理下线时间线&quot;">​</a></h3><p>在观察日 2026-07-17：</p><ul><li>7 月 16 日 brownout 已经过；</li><li>7 月 23 日 brownout 尚未发生；</li><li>7 月 30 日完全停止尚未发生。</li></ul><p>团队不得在剩余窗口中建立新的 GitHub Models 生产依赖。若已有依赖，应立即：</p><ol><li>清点 playground、catalog、API 和 BYOK 的使用；</li><li>保存请求协议、模型、评估集和预算基线；</li><li>为 7 月 23 日 brownout 验证失败处理；</li><li>在替代服务上运行相同评估集；</li><li>验证身份、密钥、速率、数据处理和费用；</li><li>在 7 月 30 日前切换并删除无用密钥；</li><li>保留回滚边界，但不把即将关闭的服务当作长期回滚目标。</li></ol><h3 id="_6-输出" tabindex="-1">6. 输出 <a class="header-anchor" href="#_6-输出" aria-label="Permalink to &quot;6. 输出&quot;">​</a></h3><p><strong>事实</strong>：GitHub Models 的完整服务范围计划于 2026-07-30 停止；Copilot 在观察日有公开计划、模型与计费文档；12 个 Business 席位的公开基础费用按页面价格计算为 228 美元/月。</p><p><strong>推断</strong>：GitHub Models 的剩余生命周期不足以支持新的生产依赖；Copilot 可能覆盖团队的代码协作任务，但并非 GitHub Models 推理 API 的等价替代。</p><p><strong>假设</strong>：在组织策略允许、用量预算明确且人工审查保留的前提下，Copilot 可以降低三个选定任务的处理时间，而不提高缺陷和安全风险。</p><p><strong>决策</strong>：拒绝把 GitHub Models 用于新依赖；为 Copilot 开启限定仓库、限定席位和限定预算的试验；未验证前不签署效果承诺。</p><p><strong>未支持主张</strong>：Copilot 一定更便宜；所有模型对全部计划可用；一般可用等于 SLA；供应商演示能代表私有仓库；推荐替代能无损迁移现有 API。</p><h3 id="_7-验证" tabindex="-1">7. 验证 <a class="header-anchor" href="#_7-验证" aria-label="Permalink to &quot;7. 验证&quot;">​</a></h3><p>试验至少运行两个正常任务和一个失败任务：</p><ol><li>核对购买资格、计划、税费、包含量与预算控制；</li><li>在目标组织确认策略、席位和模型可见性；</li><li>保存相同任务的人工基线；</li><li>用固定测试、静态检查和人工审查验证 diff；</li><li>从账单或用量报告读取 credits 与 Actions 分钟；</li><li>禁用一个模型或耗尽测试预算，观察错误与恢复；</li><li>检查取消席位、导出使用记录和退出流程；</li><li>把实测结果与文档逐项比对，记录不一致。</li></ol><p>验收条件由团队预先定义，例如：任务成功率不低于人工基线，严重缺陷为零，人工返工时间下降，峰值成本在预算内，禁用后可回到普通 Git 流程。</p><h3 id="_8-失败分支" tabindex="-1">8. 失败分支 <a class="header-anchor" href="#_8-失败分支" aria-label="Permalink to &quot;8. 失败分支&quot;">​</a></h3><p>若目标组织无法购买或管理员策略禁止所需能力，则“计划页存在”不改变不可获得事实；决策改为等待或比较替代方案。</p><p>若试验显示代码审查的 Actions 分钟与 AI credits 使峰值成本超预算，应限制触发范围、选择不同模型或停止该任务，而不是只看席位费。</p><p>若模型在试验期间进入退役计划，必须用推荐替代重新运行评估；历史成功率不能直接继承。</p><p>若生成 diff 在功能测试通过但安全审查失败，不能用平均成功率掩盖高严重度错误；保留人工审查或停止自动提交。</p><p>若下线替代缺少 API、数据区域或身份能力，则迁移方案失败。团队应选择另一供应商、降级到非 AI 工作流或缩小功能，而不是在截止日后依赖未承诺兼容。</p><h2 id="十、个人学习者的非访谈路径" tabindex="-1">十、个人学习者的非访谈路径 <a class="header-anchor" href="#十、个人学习者的非访谈路径" aria-label="Permalink to &quot;十、个人学习者的非访谈路径&quot;">​</a></h2><p>个人可以在不访谈用户、不接触内部销售材料的情况下完成一次产品证据审计：</p><ol><li>选择自己每天真实执行的任务；</li><li>保存观察日的定价、文档、更新日志和下线公告；</li><li>用自己的合规测试数据运行免费层或试用；</li><li>记录正常、权限、超限、失败和恢复；</li><li>按典型、峰值和失败负载计算成本；</li><li>与现有脚本、手工流程或不使用软件的方式比较；</li><li>把事实、观察、推断和假设分开；</li><li>设置退出条件，例如费用上限、模型退役或导出不可用。</li></ol><p>非软件替代也要进入比较：继续人工审查、减少任务范围、使用现有编辑器和 Git 命令，可能比增加一个持续变化的依赖更合适。</p><h2 id="十一、检查表与练习" tabindex="-1">十一、检查表与练习 <a class="header-anchor" href="#十一、检查表与练习" aria-label="Permalink to &quot;十一、检查表与练习&quot;">​</a></h2><h3 id="证据检查" tabindex="-1">证据检查 <a class="header-anchor" href="#证据检查" aria-label="Permalink to &quot;证据检查&quot;">​</a></h3><ul><li>[ ] 观察日期、地区、币种、税费和周期明确。</li><li>[ ] 席位、用量、token、存储和关联基础设施分开。</li><li>[ ] 文档能力包含计划、权限、客户端和限制。</li><li>[ ] 未亲测能力保持“未验证”。</li><li>[ ] 更新日志已与当前文档和目标账号核对。</li><li>[ ] 下线的宣布、停止新建、brownout 和完全停止日期分开。</li><li>[ ] 推荐替代没有默认写成功能等价。</li><li>[ ] 能力、可获得性和合同承诺分开。</li><li>[ ] 事实、观察、推断和假设分开。</li><li>[ ] 有明确的退出和非软件降级路径。</li></ul><h3 id="练习" tabindex="-1">练习 <a class="header-anchor" href="#练习" aria-label="Permalink to &quot;练习&quot;">​</a></h3><p>选择一个有订阅和用量计费的软件能力，提交一份联合证据包：</p><ol><li>一张固定地区、币种和观察日的套餐表；</li><li>典型、峰值和失败负载的成本公式；</li><li>一项文档化能力的前置、输入、输出和限制；</li><li>一个包含正常、权限不足、超限和恢复的演示协议；</li><li>两条更新日志组成的状态时间线；</li><li>一项已弃用或下线能力的迁移表；</li><li>三条事实、两条推断和一个可推翻假设；</li><li>一个不购买软件也能完成任务的替代方案。</li></ol><p>完成标准：其他读者能复算费用；每项能力都能指出证据类型；任何未观察结果都没有伪装成实测；至少一个失败分支会改变采用、预算或迁移决策。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.github.com/en/copilot/get-started/plans" target="_blank" rel="noreferrer">GitHub Docs：Plans for GitHub Copilot</a>（访问日期：2026-07-17）</li><li><a href="https://docs.github.com/en/copilot/reference/copilot-billing/models-and-pricing" target="_blank" rel="noreferrer">GitHub Docs：Models and pricing for GitHub Copilot</a>（访问日期：2026-07-17）</li><li><a href="https://docs.github.com/en/copilot/reference/ai-models/supported-models" target="_blank" rel="noreferrer">GitHub Docs：Supported AI models in GitHub Copilot</a>（访问日期：2026-07-17）</li><li><a href="https://github.blog/changelog/2026-06-17-github-copilot-app-generally-available/" target="_blank" rel="noreferrer">GitHub Changelog：GitHub Copilot app generally available</a>（访问日期：2026-07-17）</li><li><a href="https://github.blog/changelog/2026-07-01-github-models-is-being-fully-retired-on-july-30-2026/" target="_blank" rel="noreferrer">GitHub Changelog：GitHub Models is being fully retired on July 30, 2026</a>（访问日期：2026-07-17）</li></ul>`,141)])])}const b=i(s,[["render",n]]);export{c as __pageData,b as default};
